8	// renderInstructionsForGuardrails returns the post-{{.AttemptDir}}-substitution
9	// instructions string for the given harness selector. Guardrail tests assert
10	// on this pre-XML-escape form so substring checks against `<bead-id>`,
11	// `<specific-paths>`, etc. are not distorted by XML entity encoding (the
12	// rendered prompt encloses instructions in <instructions>...</instructions>
13	// and so escapes angle brackets and apostrophes). The bead body itself is
14	// excluded — invariants must come from the static prompt, not the bead.
15	func renderInstructionsForGuardrails(t *testing.T, harness, contextBudget string) string {
16		t.Helper()
17		const attemptDir = ".ddx/executions/20260101T000000-guardrails"
18		raw := executeBeadInstructionsText(harness)
19		return strings.ReplaceAll(raw, "{{.AttemptDir}}", attemptDir)
20	}
21	
22	// renderFullPromptForGuardrails returns the byte-for-byte rendered prompt
23	// (XML-wrapped, attempt-dir-substituted) for the given harness and
24	// contextBudget. Used by tests that need to verify buildPrompt-level
25	// behaviour (governing fallback, minimal-budget gating).
26	func renderFullPromptForGuardrails(t *testing.T, harness, contextBudget string) string {
27		t.Helper()
28		const attemptID = "20260101T000000-guardrails"
29		arts := &executeBeadArtifacts{
30			DirRel:      ".ddx/executions/" + attemptID,
31			PromptRel:   ".ddx/executions/" + attemptID + "/prompt.md",
32			ManifestRel: ".ddx/executions/" + attemptID + "/manifest.json",
33			ResultRel:   ".ddx/executions/" + attemptID + "/result.json",
34			ChecksRel:   ".ddx/executions/" + attemptID + "/checks.json",
35			UsageRel:    ".ddx/executions/" + attemptID + "/usage.json",
36		}
37		b := representativePromptBead()
38		content, _, err := buildPrompt(t.TempDir(), b, nil, arts, "deadbeefdeadbeef", "", harness, contextBudget)
39		if err != nil {
40			t.Fatalf("buildPrompt(%s, %q): %v", harness, contextBudget, err)
41		}
42		return string(content)
43	}
