45	// TestExecuteBeadInstructionsLoadBearingGuardrails enforces FEAT-022's
46	// static-prompt minimum-prompt rule: every guardrail listed in the
47	// file-level comment block above the constants in execute_bead.go MUST
48	// appear in the rendered prompt for each (harness, variant). This is the
49	// regression test for the comment-list contract — adding a new guardrail
50	// requires adding it to BOTH the comment block AND this list.
51	func TestExecuteBeadInstructionsLoadBearingGuardrails(t *testing.T) {
52		// Each entry: a substring (or substring family) that proves the
53		// corresponding guardrail survived the rewrite. Substrings are picked
54		// to be robust to wording shuffles within the same guardrail.
55		type guardrail struct {
56			name     string
57			any      []string // pass if ANY of these substrings is present
58			variants []string // empty = both; "claude" or "agent" = that variant only
59		}
60		guardrails := []guardrail{
61			{name: "ac_anti_handwave", any: []string{
62				"every AC must be provably satisfied",
63				"Every AC must be satisfied by code",
64			}},
65			{name: "read_first", any: []string{"Read first"}},
66			{name: "commit_subject_bead_id", any: []string{"[<bead-id>]"}},
67			{name: "commit_exactly_once", any: []string{"Commit exactly once", "commit exactly once"}},
68			{name: "git_add_specific_paths", any: []string{"git add <specific-paths>"}},
69			{name: "no_git_add_dash_a", any: []string{"never `git add -A`", "never git add -A"}},
70			{name: "no_red_code", any: []string{"Do not commit red code"}},
71			{name: "no_modify_outside_scope", any: []string{"outside the bead's scope", "outside the bead's named scope"}},
72			{name: "never_ddx_init", any: []string{"Never run `ddx init`", "never `ddx init`"}},
73			{name: "executions_intact", any: []string{".ddx/executions/"}},
74			{name: "no_rewrite_claude_md", any: []string{"CLAUDE.md, AGENTS.md"}},
75			{name: "bead_overrides_defaults", any: []string{"override CLAUDE.md", "overrides project defaults"}},
76			{name: "reports_attempt_dir", any: []string{".ddx/executions/20260101T000000-guardrails/"}},
77			{name: "reports_no_tmp", any: []string{"/tmp"}},
78			{name: "no_changes_rationale", any: []string{"no_changes_rationale.txt"}},
79			{name: "step0_size_check", any: []string{"## Step 0: size check"}},
80			{name: "step0_large_description_hint", any: []string{"exceeds 8000 bytes", "split-first pass"}},
81			{name: "step0_depth_cap", any: []string{"Auto-decomposition is capped at depth 2", "third-level split"}},
82			{name: "decompose_bead_create", any: []string{"ddx bead create"}},
83			{name: "decompose_bead_dep_add", any: []string{"ddx bead dep add"}},
84			{name: "decompose_bead_update", any: []string{"ddx bead update"}},
85			{name: "review_is_a_gate", any: []string{"review is a gate", "review is a gate, not an escape hatch"}},
86			{name: "blocking_review_findings", any: []string{"BLOCKING `<review-findings>`", "BLOCKING <review-findings>"}},
87			{name: "no_no_changes_with_blocking", any: []string{"do not declare `no_changes` with blocking findings open"}},
88			{name: "stop_after_commit", variants: []string{"agent"}, any: []string{"Stop immediately after the commit"}},
89			{name: "agent_use_tools_not_bash", variants: []string{"agent"}, any: []string{"`bash: cat`", "`bash: rg`"}},
90		}
91	
92		cases := []struct{ variant, harness string }{
93			{"claude", "claude"},
94			{"agent", "agent"},
95		}
96		for _, c := range cases {
97			c := c
98			t.Run(c.variant, func(t *testing.T) {
99				rendered := renderInstructionsForGuardrails(t, c.harness, "")
100				for _, g := range guardrails {
101					if len(g.variants) > 0 && !contains(g.variants, c.variant) {
102						continue
103					}
104					if !anyContains(rendered, g.any) {
105						t.Errorf("guardrail %q missing from %s variant; expected one of %v",
106							g.name, c.variant, g.any)
107					}
108				}
109			})
110		}
111	}
