113	// TestExecuteBeadInstructionsHarnessSelector covers the routing at
114	// executeBeadInstructionsText: agent/fiz/embedded route to the Agent
115	// variant; claude/codex/opencode/unknown/empty route to the Claude
116	// variant. AC10 forbids any new per-harness branches beyond Claude/Agent.
117	func TestExecuteBeadInstructionsHarnessSelector(t *testing.T) {
118		cases := []struct {
119			harness string
120			want    string // "agent" or "claude"
121		}{
122			{"agent", "agent"},
123			{"fiz", "agent"},
124			{"embedded", "agent"},
125			{"AGENT", "agent"},
126			{"  Fiz  ", "agent"},
127	
128			{"claude", "claude"},
129			{"codex", "claude"},
130			{"opencode", "claude"},
131			{"unknown", "claude"},
132			{"", "claude"},
133			{"GPT-4", "claude"},
134		}
135		for _, c := range cases {
136			c := c
137			t.Run(c.harness+"_to_"+c.want, func(t *testing.T) {
138				got := executeBeadInstructionsText(c.harness)
139				switch c.want {
140				case "agent":
141					if got != executeBeadInstructionsAgentText {
142						t.Errorf("harness %q: expected Agent variant, got Claude", c.harness)
143					}
144				case "claude":
145					if got != executeBeadInstructionsClaudeText {
146						t.Errorf("harness %q: expected Claude variant, got Agent", c.harness)
147					}
148				}
149			})
150		}
151	}
