153	func TestExecuteBeadInstructionsContainsBeadExecutionMode(t *testing.T) {
154		cases := []struct{ variant, harness string }{
155			{"claude", "claude"},
156			{"agent", "agent"},
157		}
158		for _, c := range cases {
159			c := c
160			t.Run(c.variant, func(t *testing.T) {
161				rendered := renderInstructionsForGuardrails(t, c.harness, "")
162				for _, sub := range []string{
163					"DDX_MODE=bead_execution",
164					"edit code/docs for bead AC",
165					"Only broad queue-steward default is overridden",
166					"tracker, merge-policy, verification, safety stay active",
167				} {
168					if !strings.Contains(rendered, sub) {
169						t.Errorf("rendered %s prompt missing execution-mode substring %q", c.variant, sub)
170					}
171				}
172			})
173		}
174	}
