176	// TestExecuteBeadInstructionsRenderedInvariants is the AC4 substring-invariant
177	// test: rendered prompts MUST contain the named substrings in every (variant,
178	// non-minimal contextBudget) pair. These are the operational primitives the
179	// agent has to know about; if a tightening pass drops one, the bead loop
180	// silently degrades.
181	func TestExecuteBeadInstructionsRenderedInvariants(t *testing.T) {
182		cases := []struct{ variant, harness string }{
183			{"claude", "claude"},
184			{"agent", "agent"},
185		}
186		required := []string{
187			"[<bead-id>]",
188			"git add <specific-paths>",
189			"git add -A", // appears as part of "never `git add -A`"
190			"no_changes_rationale.txt",
191			".ddx/executions/",
192			"ddx bead create",
193			"ddx bead dep add",
194			"ddx bead update",
195			"Auto-decomposition is capped at depth 2",
196		}
197		for _, c := range cases {
198			c := c
199			t.Run(c.variant, func(t *testing.T) {
200				rendered := renderInstructionsForGuardrails(t, c.harness, "")
201				for _, sub := range required {
202					if !strings.Contains(rendered, sub) {
203						t.Errorf("rendered %s prompt missing required substring %q", c.variant, sub)
204					}
205				}
206			})
207		}
208	}
