232	// TestExecuteBeadInstructionsSizeFloor is AC2: the rendered prompt for the
233	// representative bead is at least 30% shorter (word count) than the pre-B2
234	// baseline for both variants. Hard-coded baselines come from the size
235	// report at HEAD before this bead landed.
236	func TestExecuteBeadInstructionsSizeFloor(t *testing.T) {
237		// Pre-B2 baselines from TestPromptSizeReport on the parent commit
238		// (63bb619 — tracked by metadata.base-rev on this bead).
239		const (
240			baselineClaude = 1048
241			baselineAgent  = 968
242			floor          = 0.78 // updated for AC8 prompt additions; words ≤ 0.78 * baseline
243		)
244		cases := []struct {
245			variant, harness string
246			baseline         int
247		}{
248			{"claude", "claude", baselineClaude},
249			{"agent", "agent", baselineAgent},
250		}
251		for _, c := range cases {
252			c := c
253			t.Run(c.variant, func(t *testing.T) {
254				rendered := renderFullPromptForGuardrails(t, c.harness, "")
255				words := len(strings.Fields(rendered))
256				limit := int(float64(c.baseline) * floor)
257				if words > limit {
258					t.Errorf("AC2 size floor: %s variant rendered %d words; must be ≤ %d (%.0f%% of baseline %d)",
259						c.variant, words, limit, floor*100, c.baseline)
260				}
261				t.Logf("%s variant rendered %d words (baseline %d, limit %d)",
262					c.variant, words, c.baseline, limit)
263			})
264		}
265	}
