267	func contains(haystack []string, needle string) bool {
268		for _, h := range haystack {
269			if h == needle {
270				return true
271			}
272		}
273		return false
274	}
275	
276	func anyContains(s string, needles []string) bool {
277		for _, n := range needles {
278			if strings.Contains(s, n) {
279				return true
280			}
281		}
282		return false
283	}
