11	// TestDDxAgentModeGuidance_DocContract asserts that the three governing
12	// documents (AGENTS.md, FEAT-010, FEAT-011) together name all four
13	// DDX_MODE values and include the ddx work carve-out that separates
14	// interactive queue stewardship from worker execution.
15	func TestDDxAgentModeGuidance_DocContract(t *testing.T) {
16		_, filename, _, _ := runtime.Caller(0)
17		repoRoot := filepath.Join(filepath.Dir(filename), "..", "..")
18	
19		fourModes := []string{
20			"queue_steward",
21			"bead_execution",
22			"direct_user_implementation",
23			"review",
24		}
25	
26		// --- AGENTS.md ---
27		agentsPath := filepath.Join(repoRoot, "AGENTS.md")
28		agentsBytes, err := os.ReadFile(agentsPath)
29		if err != nil {
30			t.Fatalf("AGENTS.md must be readable: %v", err)
31		}
32		agents := string(agentsBytes)
33	
34		defaultModeIdx := strings.Index(agents, "Default Interactive Mode")
35		if defaultModeIdx == -1 {
36			t.Fatal("AGENTS.md must contain a 'Default Interactive Mode' section")
37		}
38		beadPolicyIdx := strings.Index(agents, "## Bead Policy")
39		if beadPolicyIdx == -1 {
40			t.Fatal("AGENTS.md must contain a '## Bead Policy' section")
41		}
42		if defaultModeIdx >= beadPolicyIdx {
43			t.Errorf("AGENTS.md: 'Default Interactive Mode' (pos %d) must appear before '## Bead Policy' (pos %d)",
44				defaultModeIdx, beadPolicyIdx)
45		}
46	
47		for _, mode := range fourModes {
48			if !strings.Contains(agents, mode) {
49				t.Errorf("AGENTS.md must name mode %q", mode)
50			}
51		}
52		if !strings.Contains(agents, "ddx work") {
53			t.Error("AGENTS.md must include the ddx work carve-out")
54		}
55	
56		// --- FEAT-010 ---
57		feat010Path := filepath.Join(repoRoot, "docs/helix/01-frame/features/FEAT-010-task-execution.md")
58		feat010Bytes, err := os.ReadFile(feat010Path)
59		if err != nil {
60			t.Fatalf("FEAT-010 must be readable: %v", err)
61		}
62		feat010 := string(feat010Bytes)
63	
64		for _, mode := range fourModes {
65			if !strings.Contains(feat010, mode) {
66				t.Errorf("FEAT-010 must define mode %q", mode)
67			}
68		}
69		if !strings.Contains(feat010, "DDX_MODE") {
70			t.Error("FEAT-010 must name DDX_MODE")
71		}
72		if !strings.Contains(feat010, "precedence") && !strings.Contains(feat010, "Precedence") {
73			t.Error("FEAT-010 must define precedence rules for the modes")
74		}
75		if !strings.Contains(feat010, "ddx work") {
76			t.Error("FEAT-010 must reference ddx work in the mode taxonomy")
77		}
78	
79		// --- FEAT-011 ---
80		feat011Path := filepath.Join(repoRoot, "docs/helix/01-frame/features/FEAT-011-skills.md")
81		feat011Bytes, err := os.ReadFile(feat011Path)
82		if err != nil {
83			t.Fatalf("FEAT-011 must be readable: %v", err)
84		}
85		feat011 := string(feat011Bytes)
86	
87		if !strings.Contains(feat011, "queue_steward") {
88			t.Error("FEAT-011 must reference queue_steward mode")
89		}
90		if !strings.Contains(feat011, "bead_execution") {
91			t.Error("FEAT-011 must reference bead_execution mode")
92		}
93		if !strings.Contains(feat011, "ddx work") {
94			t.Error("FEAT-011 must describe routing for explicit ddx work execution prompts")
95		}
